import { describe, test, expect, beforeEach } from 'bun:test';
import { BettyCompiler } from '../betty/compiler.js';

describe('BettyCompiler', () => {
    let compiler: BettyCompiler;

    beforeEach(() => {
        compiler = new BettyCompiler();
    });

    describe('node parsing', () => {
        test('parses simple node with label', () => {
            const { ast } = compiler.parse(`
                (input: Source { data: 'hello' })
                (input)-[:PROCESS]->(output)
            `);
            expect(ast).not.toBeNull();
            const node = ast!.nodes.get('input');
            expect(node).toBeDefined();
            expect(node!.labels).toContain('Source');
            expect(node!.properties['data']).toBe('hello');
        });

        test('parses node without label', () => {
            const { ast } = compiler.parse(`
                (a)-[:PROCESS]->(b)
            `);
            expect(ast).not.toBeNull();
            expect(ast!.nodes.has('a')).toBe(true);
            expect(ast!.nodes.get('a')!.labels).toEqual([]);
        });

        test('parses node with multiple properties', () => {
            const { ast } = compiler.parse(`
                (encoder: Linear { weights: 'weights.toml', section: 'l1' })
                (encoder)-[:PROCESS]->(out)
            `);
            const node = ast!.nodes.get('encoder');
            expect(node!.properties['weights']).toBe('weights.toml');
            expect(node!.properties['section']).toBe('l1');
        });

        test('updates existing node with new label', () => {
            const { ast } = compiler.parse(`
                (x: Alpha)
                (x: Beta)
                (x)-[:PROCESS]->(y)
            `);
            const node = ast!.nodes.get('x');
            expect(node!.labels).toContain('Alpha');
            expect(node!.labels).toContain('Beta');
        });
    });

    describe('edge parsing', () => {
        test('parses PROCESS edge', () => {
            const { ast } = compiler.parse(`(a)-[:PROCESS]->(b)`);
            expect(ast).not.toBeNull();
            expect(ast!.edges).toHaveLength(1);
            expect(ast!.edges[0].type).toBe('PROCESS');
            expect(ast!.edges[0].sourceIds).toEqual(['a']);
            expect(ast!.edges[0].targetIds).toEqual(['b']);
        });

        test('parses FORK edge with multiple targets', () => {
            const { ast } = compiler.parse(`(a)-[:FORK]->(b | c | d)`);
            expect(ast!.edges[0].type).toBe('FORK');
            expect(ast!.edges[0].targetIds).toHaveLength(3);
            expect(ast!.edges[0].targetIds).toEqual(['b', 'c', 'd']);
        });

        test('parses FOLD edge with multiple sources', () => {
            const { ast } = compiler.parse(`
                (a)-[:FORK]->(b | c)
                (b | c)-[:FOLD { strategy: 'merge-all' }]->(d)
            `);
            const foldEdge = ast!.edges.find(e => e.type === 'FOLD');
            expect(foldEdge).toBeDefined();
            expect(foldEdge!.sourceIds).toEqual(['b', 'c']);
            expect(foldEdge!.properties['strategy']).toBe('merge-all');
        });

        test('parses RACE edge', () => {
            const { ast } = compiler.parse(`
                (a)-[:FORK]->(b | c)
                (b | c)-[:RACE]->(winner)
            `);
            const raceEdge = ast!.edges.find(e => e.type === 'RACE');
            expect(raceEdge).toBeDefined();
            expect(raceEdge!.sourceIds).toEqual(['b', 'c']);
        });

        test('parses VENT edge', () => {
            const { ast } = compiler.parse(`
                (a)-[:FORK]->(b | c)
                (c)-[:VENT]->(waste)
            `);
            const ventEdge = ast!.edges.find(e => e.type === 'VENT');
            expect(ventEdge).toBeDefined();
        });

        test('parses INTERFERE edge with mode', () => {
            const { ast } = compiler.parse(`
                (a | b)-[:INTERFERE { mode: 'constructive' }]->(c)
            `);
            const edge = ast!.edges[0];
            expect(edge.type).toBe('INTERFERE');
            expect(edge.properties['mode']).toBe('constructive');
        });

        test('parses chained edges', () => {
            const { ast } = compiler.parse(`
                (a)-[:PROCESS]->(b)-[:PROCESS]->(c)
            `);
            expect(ast!.edges).toHaveLength(2);
            expect(ast!.edges[0].sourceIds).toEqual(['a']);
            expect(ast!.edges[0].targetIds).toEqual(['b']);
            expect(ast!.edges[1].sourceIds).toEqual(['b']);
            expect(ast!.edges[1].targetIds).toEqual(['c']);
        });

        test('auto-registers nodes from edges', () => {
            const { ast } = compiler.parse(`(x)-[:PROCESS]->(y)`);
            expect(ast!.nodes.has('x')).toBe(true);
            expect(ast!.nodes.has('y')).toBe(true);
        });
    });

    describe('beta1 tracking', () => {
        test('FORK increases beta1 by targets-1', () => {
            compiler.parse(`(a)-[:FORK]->(b | c | d)`);
            expect(compiler.getBettiNumber()).toBe(2);
        });

        test('FOLD decreases beta1 by sources-1', () => {
            compiler.parse(`
                (a)-[:FORK]->(b | c | d)
                (b | c | d)-[:FOLD]->(e)
            `);
            expect(compiler.getBettiNumber()).toBe(0);
        });

        test('COLLAPSE is alias for FOLD', () => {
            compiler.parse(`
                (a)-[:FORK]->(b | c)
                (b | c)-[:COLLAPSE]->(e)
            `);
            expect(compiler.getBettiNumber()).toBe(0);
        });

        test('RACE preserves beta1 (homotopy equivalence)', () => {
            compiler.parse(`
                (a)-[:FORK]->(b | c)
                (b | c)-[:RACE]->(winner)
            `);
            expect(compiler.getBettiNumber()).toBe(1);
        });

        test('VENT decreases beta1 by 1', () => {
            compiler.parse(`
                (a)-[:FORK]->(b | c)
                (c)-[:VENT]->(waste)
            `);
            expect(compiler.getBettiNumber()).toBe(0);
        });

        test('TUNNEL decreases beta1 by 1', () => {
            compiler.parse(`
                (a)-[:FORK]->(b | c)
                (c)-[:TUNNEL]->(exit)
            `);
            expect(compiler.getBettiNumber()).toBe(0);
        });

        test('beta1 never goes negative', () => {
            compiler.parse(`
                (a)-[:VENT]->(b)
            `);
            expect(compiler.getBettiNumber()).toBe(0);
        });

        test('PROCESS does not change beta1', () => {
            compiler.parse(`(a)-[:PROCESS]->(b)`);
            expect(compiler.getBettiNumber()).toBe(0);
        });

        test('complex topology: fork-fork-fold-fold returns to zero', () => {
            compiler.parse(`
                (a)-[:FORK]->(b | c)
                (b)-[:FORK]->(d | e)
                (d | e)-[:FOLD]->(f)
                (c | f)-[:FOLD]->(g)
            `);
            expect(compiler.getBettiNumber()).toBe(0);
        });

        test('multi-head attention topology', () => {
            // Fork 4 heads, fold back: beta1 should be 0
            compiler.parse(`
                (qkv)-[:FORK]->(h1 | h2 | h3 | h4)
                (h1 | h2 | h3 | h4)-[:FOLD { strategy: 'concat' }]->(out)
            `);
            expect(compiler.getBettiNumber()).toBe(0);
        });
    });

    describe('comment handling', () => {
        test('strips single-line comments', () => {
            const { ast } = compiler.parse(`
                // This is a comment
                (a)-[:PROCESS]->(b)
                // Another comment
            `);
            expect(ast).not.toBeNull();
            expect(ast!.edges).toHaveLength(1);
        });
    });

    describe('imperative code rejection', () => {
        test('rejects function keyword', () => {
            const { ast, output } = compiler.parse(`function foo() {}`);
            expect(ast).toBeNull();
            expect(output).toContain('Imperative code rejected');
        });

        test('rejects arrow functions', () => {
            const { ast } = compiler.parse(`const f = () => 42`);
            expect(ast).toBeNull();
        });

        test('rejects return statements', () => {
            const { ast } = compiler.parse(`return result`);
            expect(ast).toBeNull();
        });
    });

    describe('edge cases', () => {
        test('empty input returns null AST', () => {
            const { ast, output } = compiler.parse('');
            expect(ast).toBeNull();
            expect(output).toBe('');
        });

        test('whitespace-only input returns null AST', () => {
            const { ast } = compiler.parse('   \n  \n  ');
            expect(ast).toBeNull();
        });

        test('EXECUTE command returns current AST', () => {
            const { ast, output } = compiler.parse('EXECUTE');
            expect(ast).not.toBeNull();
            expect(output).toContain('Queuing execution');
        });

        test('invalid input without edges gives guidance', () => {
            const { ast, output } = compiler.parse('hello world');
            expect(ast).toBeNull();
            expect(output).toContain('Awaiting valid topology graph');
        });
    });

    describe('full topology parsing', () => {
        test('parses ai_hello.gg topology', () => {
            const { ast, b1 } = compiler.parse(`
                (input: Source { data: '[0.1, 0.5, -0.2]' })
                (encoder: Linear { weights: 'weights.toml', section: 'l1' })
                (relu: Activation { type: 'relu' })
                (head1: Attention { section: 'attention' })
                (head2: Attention { section: 'attention' })
                (decoder: Linear { weights: 'weights.toml', section: 'l2' })
                (output: Softmax)
                (input)-[:PROCESS]->(encoder)-[:PROCESS]->(relu)
                (relu)-[:FORK]->(head1 | head2)
                (head1 | head2)-[:FOLD { strategy: 'merge-all' }]->(context)
                (context)-[:PROCESS]->(decoder)-[:PROCESS]->(output)
                (output)-[:PROCESS]->(prediction)
            `);

            expect(ast).not.toBeNull();
            expect(ast!.nodes.size).toBeGreaterThanOrEqual(7);
            expect(ast!.nodes.get('input')!.labels).toContain('Source');
            expect(ast!.nodes.get('encoder')!.labels).toContain('Linear');
            expect(ast!.nodes.get('relu')!.labels).toContain('Activation');
            expect(b1).toBe(0); // Fork 2, fold 2 — balanced
        });

        test('parses transformer.gg topology', () => {
            const { ast, b1 } = compiler.parse(`
                (input_sequence: Tensor { type: 'embeddings' })
                (qkv_projection: Matrix { op: 'linear_projection' })
                (head_1: Attention { d_k: '64' })
                (head_2: Attention { d_k: '64' })
                (head_3: Attention { d_k: '64' })
                (head_4: Attention { d_k: '64' })
                (ffn: Network { hidden: '2048' })
                (input_sequence)-[:PROCESS]->(qkv_projection)
                (qkv_projection)-[:FORK]->(head_1 | head_2 | head_3 | head_4)
                (head_1 | head_2 | head_3 | head_4)-[:FOLD { strategy: 'concat' }]->(multi_head_out)
                (input_sequence | multi_head_out)-[:INTERFERE { mode: 'constructive' }]->(residual_1)
                (residual_1)-[:PROCESS]->(ffn)
                (residual_1 | ffn)-[:INTERFERE { mode: 'constructive' }]->(transformer_out)
            `);

            expect(ast).not.toBeNull();
            expect(b1).toBe(0); // Fork 4, fold 4 — balanced
        });

        test('parses betti.gg self-hosted compiler topology', () => {
            const { ast, b1 } = compiler.parse(`
                (source_code)-[:PROCESS]->(read_source)-[:PROCESS]->(strip_comments)
                (strip_comments)-[:FORK]->(parse_nodes | parse_edges | parse_properties)
                (parse_nodes | parse_edges | parse_properties)-[:FOLD { strategy: 'merge-ast' }]->(ast)
                (ast)-[:PROCESS]->(build_wasm_frames)-[:PROCESS]->(executable_binary)
            `);

            expect(ast).not.toBeNull();
            expect(b1).toBe(0); // Fork 3, fold 3 — balanced
            expect(ast!.nodes.has('source_code')).toBe(true);
            expect(ast!.nodes.has('executable_binary')).toBe(true);
        });

        test('parses codec race topology', () => {
            const { ast, b1 } = compiler.parse(`
                (raw_codec: Codec { type: 'raw' })
                (brotli_codec: Codec { type: 'brotli' })
                (input)-[:FORK]->(raw_codec | brotli_codec)
                (raw_codec | brotli_codec)-[:RACE]->(winner)
            `);

            expect(ast).not.toBeNull();
            // FORK +1, RACE preserves — beta1 = 1
            expect(b1).toBe(1);
        });
    });
});
